mapper.select:
SELECT a.store_id, a.activity_id, a.p_id, a.is_display, a.sort, a.add_date, a.product_title, a.imgurl, a.num, a.pid, a.mch_status, a.recycle, a.product_class, a.price FROM ( SELECT pro.store_id, pro.activity_id, pro.p_id, pro.is_display, pro.sort, pro.add_date, a.product_title, a.imgurl, c.num, c.pid, c.recycle as crecycle, a.mch_status, a.recycle, a.product_class, min(c.price) over(partition by c.pid) AS price, ROW_NUMBER() over(partition by c.pid) AS top FROM lkt_activity_pro pro inner JOIN lkt_product_list AS a on pro.p_id=a.id left JOIN lkt_configure AS c ON a.id = c.pid ) AS a
and a.top <2 AND a.activity_id = #{activityId} and a.p_id=a.id AND a.store_id = #{store_id} AND a.product_class LIKE CONCAT('%-', #{cid},'-%')
#{id}
AND a.mch_status = 2 AND a.recycle = 0 AND a.active = 1 AND a.crecycle = 0
a.sort ${sort_sort} a.sort DESC
LIMIT #{page},#{pageSize}

SELECT a.id, a.cover_map, a.product_title, a.imgurl, a.status, a.volume, a.price, a.yprice, a.s_type FROM ( SELECT a.id, a.cover_map, a.product_title, a.imgurl, a.status, IF ( a.volume < 0, 0, a.volume )+ a.real_volume AS volume, a.s_type, min( c.price ) over(partition by c.pid) AS price, c.yprice, ROW_NUMBER() over(partition by c.pid) AS top FROM lkt_activity_pro AS b LEFT JOIN lkt_product_list AS a ON b.p_id = a.id RIGHT JOIN lkt_configure AS c ON a.id = c.pid WHERE b.store_id = #{storeId} AND b.activity_id = #{aId} AND b.is_display = 1 AND a.store_id = #{storeId} AND a.mch_status = 2 AND a.recycle = 0 AND a.active = 1
#{status,jdbcType=INTEGER}
ORDER BY b.sort DESC ) AS a WHERE a.top = 1
